import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Read a whole line instead of just a token

        char[] buffer = new char[10];

        // Copy the user input into the buffer with boundary check
        for (int i = 0; i < Math.min(input.length(), buffer.length); i++) {
            buffer[i] = input.charAt(i);
        }

        // Ensure that the buffer is properly initialized
        for (int i = Math.min(input.length(), buffer.length); i < buffer.length; i++) {
            buffer[i] = '\0'; // Fill remaining space with null characters
        }

        System.out.println("User input copied into buffer: " + new String(buffer));
    }
}

### Explanation:
